import React from 'react'
import { Background } from 'reactflow'
import { Handle } from 'reactflow'

export const BaseNode = ({title, handles ,children }) => {
  return (
    <div>
        <div>{title}</div>
        {children}

       {handles.map((handle)=>
       <Handle
        key={handle.key}
       type={handle.type}
       id={handle.id}
       style={handle.style||{}}
       ></Handle>)}
    </div>
  )
}
